pub fn concurrent_purchase_example(
    inventory: Arc<Inventory>,
    sku: String,
    qty: u32,
    threads: usize,
) -> Vec<PurchaseResult> {
    let mut handles = Vec::with_capacity(threads);
    for _ in 0..threads {
        let inv = Arc::clone(&inventory);
        let s = sku.clone();
        handles.push(std::thread::spawn(move || inv.try_purchase(&s, qty)));
    }
    handles
        .into_iter()
        .map(|h| h.join().unwrap())
        .collect()
}